<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Bouncing Ball Playground</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #0b1020;
      --panel: #131b31;
      --panel-border: #263454;
      --text: #e8efff;
      --muted: #91a0c2;
      --accent: #67d7ff;
      --accent-2: #9d7bff;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      min-height: 100vh;
      display: grid;
      place-items: center;
      padding: 24px;
      color: var(--text);
      background:
        radial-gradient(circle at 50% 0%, #19264a 0%, transparent 44%),
        var(--bg);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    .wrap {
      width: min(92vw, 760px);
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 16px;
    }

    h1 {
      margin: 0;
      font-size: clamp(1.45rem, 4vw, 2.2rem);
      letter-spacing: 0.03em;
      text-shadow: 0 0 24px rgba(103, 215, 255, 0.3);
    }

    .hint {
      margin: -8px 0 0;
      color: var(--muted);
      font-size: 0.92rem;
      text-align: center;
    }

    canvas {
      display: block;
      width: 640px;
      height: 480px;
      max-width: 92vw;
      aspect-ratio: 4 / 3;
      border: 2px solid #33456f;
      border-radius: 14px;
      background: #09101f;
      box-shadow:
        0 0 0 5px rgba(40, 61, 106, 0.18),
        0 18px 55px rgba(0, 0, 0, 0.46),
        inset 0 0 35px rgba(30, 75, 140, 0.18);
      cursor: crosshair;
    }

    .controls {
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 10px;
    }

    button {
      border: 1px solid var(--panel-border);
      border-radius: 9px;
      padding: 10px 18px;
      color: var(--text);
      background: linear-gradient(180deg, #1c2948, #151e35);
      font: inherit;
      font-weight: 650;
      cursor: pointer;
      transition: transform 0.12s ease, border-color 0.12s ease, filter 0.12s ease;
    }

    button:hover {
      filter: brightness(1.2);
      border-color: #5270aa;
    }

    button:active {
      transform: translateY(1px) scale(0.98);
    }

    #play {
      border-color: #397d9f;
      background: linear-gradient(180deg, #1d536f, #173b59);
    }
  </style>
</head>
<body>
  <main class="wrap">
    <h1>Bouncing Ball Playground</h1>
    <p class="hint">Click anywhere in the arena to launch a ball</p>

    <canvas id="sim" width="640" height="480" aria-label="Bouncing ball simulation"></canvas>

    <div class="controls">
      <button id="drop" type="button">Drop Ball</button>
      <button id="play" type="button">Play</button>
      <button id="clear" type="button">Clear</button>
    </div>
  </main>

  <script>
    (() => {
      const canvas = document.getElementById("sim");
      const ctx = canvas.getContext("2d");
      const w = canvas.width;
      const h = canvas.height;

      const gravity = 0.48;
      const restitution = 0.84;
      const ballsList = [];
      let playing = false;
      let animationId = null;

      function clamp(value, low, high) {
        return Math.max(low, Math.min(high, value));
      }

      function addBall(x, y, vx = 0, vy = 0, r) {
        const radius = Number.isFinite(r)
          ? clamp(Math.abs(r), 4, Math.min(w, h) / 2)
          : 10 + Math.random() * 7;

        const ball = {
          x: Number.isFinite(x) ? x : w / 2,
          y: Number.isFinite(y) ? y : radius + 4,
          vx: Number.isFinite(vx) ? vx : 0,
          vy: Number.isFinite(vy) ? vy : 0,
          r: radius
        };

        ball.x = clamp(ball.x, ball.r, w - ball.r);
        ball.y = clamp(ball.y, ball.r, h - ball.r);
        ballsList.push(ball);
        draw();
        return ball;
      }

      function clear() {
        ballsList.length = 0;
        draw();
      }

      function step(dt = 1) {
        dt = Number.isFinite(dt) ? Math.max(0, dt) : 1;

        for (const ball of ballsList) {
          ball.vy += gravity * dt;
          ball.x += ball.vx * dt;
          ball.y += ball.vy * dt;

          if (ball.x - ball.r < 0 || (ball.x - ball.r <= 0 && ball.vx < 0)) {
            ball.x = ball.r;
            ball.vx = Math.abs(ball.vx) * restitution;
          } else if (ball.x + ball.r > w || (ball.x + ball.r >= w && ball.vx > 0)) {
            ball.x = w - ball.r;
            ball.vx = -Math.abs(ball.vx) * restitution;
          }

          if (ball.y - ball.r < 0 || (ball.y - ball.r <= 0 && ball.vy < 0)) {
            ball.y = ball.r;
            ball.vy = Math.abs(ball.vy) * restitution;
          } else if (ball.y + ball.r > h || (ball.y + ball.r >= h && ball.vy > 0)) {
            ball.y = h - ball.r;
            ball.vy = -Math.abs(ball.vy) * restitution;
          }

          ball.x = clamp(ball.x, ball.r, w - ball.r);
          ball.y = clamp(ball.y, ball.r, h - ball.r);
        }

        draw();
      }

      function draw() {
        ctx.clearRect(0, 0, w, h);

        const gradient = ctx.createLinearGradient(0, 0, 0, h);
        gradient.addColorStop(0, "#0d1830");
        gradient.addColorStop(1, "#080e1b");
        ctx.fillStyle = gradient;
        ctx.fillRect(0, 0, w, h);

        ctx.strokeStyle = "rgba(109, 151, 218, 0.08)";
        ctx.lineWidth = 1;
        for (let x = 32; x < w; x += 32) {
          ctx.beginPath();
          ctx.moveTo(x, 0);
          ctx.lineTo(x, h);
          ctx.stroke();
        }
        for (let y = 32; y < h; y += 32) {
          ctx.beginPath();
          ctx.moveTo(0, y);
          ctx.lineTo(w, y);
          ctx.stroke();
        }

        for (const ball of ballsList) {
          const glow = ctx.createRadialGradient(
            ball.x - ball.r * 0.35, ball.y - ball.r * 0.4, 1,
            ball.x, ball.y, ball.r * 1.8
          );
          glow.addColorStop(0, "#ffffff");
          glow.addColorStop(0.18, "#b8f1ff");
          glow.addColorStop(0.55, "#55cfff");
          glow.addColorStop(1, "#756dff");

          ctx.save();
          ctx.shadowColor = "rgba(82, 203, 255, 0.85)";
          ctx.shadowBlur = 18;
          ctx.beginPath();
          ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
          ctx.fillStyle = glow;
          ctx.fill();
          ctx.restore();

          ctx.beginPath();
          ctx.arc(ball.x - ball.r * 0.3, ball.y - ball.r * 0.35, ball.r * 0.2, 0, Math.PI * 2);
          ctx.fillStyle = "rgba(255,255,255,0.72)";
          ctx.fill();
        }
      }

      function balls() {
        return ballsList.map(ball => ({ ...ball }));
      }

      window.sim = {
        w,
        h,
        balls,
        addBall,
        clear,
        step
      };

      canvas.addEventListener("click", event => {
        const rect = canvas.getBoundingClientRect();
        const scaleX = w / rect.width;
        const scaleY = h / rect.height;
        const x = (event.clientX - rect.left) * scaleX;
        const y = (event.clientY - rect.top) * scaleY;
        addBall(x, y, (Math.random() - 0.5) * 2.4, (Math.random() - 0.5) * 2.2);
      });

      document.getElementById("drop").addEventListener("click", () => {
        const r = 10 + Math.random() * 7;
        addBall(
          r + Math.random() * (w - 2 * r),
          r + 2,
          (Math.random() - 0.5) * 2,
          Math.random() * 1.5
        );
      });

      document.getElementById("clear").addEventListener("click", clear);

      const playButton = document.getElementById("play");
      playButton.addEventListener("click", () => {
        playing = !playing;
        playButton.textContent = playing ? "Pause" : "Play";

        if (playing) {
          let last = performance.now();
          const animate = now => {
            if (!playing) return;
            const dt = Math.min(2, (now - last) / 16.6667);
            last = now;
            step(dt);
            animationId = requestAnimationFrame(animate);
          };
          animationId = requestAnimationFrame(animate);
        } else if (animationId !== null) {
          cancelAnimationFrame(animationId);
          animationId = null;
        }
      });

      draw();
    })();
  </script>
</body>
</html>
